const totalPages = Math.max(1, Number($input.first().json.data.data.result) || 1);

const output = [];

for (const item of $input.all()) {
  const url = item.json.data.url;

  output.push({ json: { url } });

  for (let p = 2; p <= totalPages; p++) {
    output.push({
      json: {
        url: `${url}/pg-${p}`,
      },
    });
  }
}

return output;

const output = [];

for (const item of $input.all()) {
  const results = item.json?.data?.data?.result || [];

  for (const r of results) {
    output.push({ json: r });
  }
}

return output;
